use std::f32;

fn main() {
    let pi = std::f32::consts::PI;
    let radius = 5.00f32;

    let area = pi * f32::powi(radius, 2);
    println!("The area of a circle with radius {radius:.2} is {area:.5}!");

    let mut res = 42;
    let option = Some(12);
    if let Some(x) = option {
        res += x;
    }
    println!("Result: {res}");
}
